UPDATE dishes SET recipe = '猪肉切片，酸菜切丝。锅中热油，炒香肉片，加酸菜翻炒，放入粉条和清水烧开，加辣椒调味，煮至粉条软烂入味即成。' WHERE id = 'liaoning_fushun_botang';
UPDATE dishes SET recipe = '羊肉剁馅加大葱末和盐调匀。面粉用开水烫面和成团，擀成薄皮，包入馅料收口成烧麦状。上蒸笼大火蒸熟，皮薄馅嫩汁多。' WHERE id = 'liaoning_fushun_majia_shaomai';
UPDATE dishes SET recipe = '各种蔬菜和豆皮洗净切好。锅中烧水，放入花椒和辣椒油煮出麻辣味，下蔬菜和豆皮煮熟。连汤带菜倒入盆中，麻辣鲜香。' WHERE id = 'liaoning_fushun_malapen';
UPDATE dishes SET recipe = '土豆片、豆皮和海带焯水煮熟沥干。碗中放入芝麻酱、辣椒油和花椒油调成料汁，倒入食材拌匀，麻辣鲜香，爽口开胃。' WHERE id = 'liaoning_fushun_xianbing';
UPDATE dishes SET recipe = '猪肉剁馅加鸡汤搅拌至水馅融合，加盐调味。面粉和面擀皮，包入馅料捏成包子。上蒸笼大火蒸熟，皮薄汁多，鲜嫩可口。' WHERE id = 'liaoning_goubangzi_shuixian_baozi';
UPDATE dishes SET recipe = '童子鸡洗净，用香料和盐腌制入味，煮熟捞出。锅底铺白糖和茶叶，架上鸡熏制上色。至色泽金红、烟香浓郁即成。' WHERE id = 'liaoning_goubangzi_xunji';
UPDATE dishes SET recipe = '猪肉和牛肉混合加蔬菜末调成馅料。面粉和面擀皮，包入馅料压成饼状。放入平底锅或烤炉中烙烤至两面金黄、外酥内嫩即成。' WHERE id = 'liaoning_haicheng_xianbing';
UPDATE dishes SET recipe = '黄豆磨浆煮开，用卤水点成嫩豆腐脑盛碗。淋上芝麻酱和辣椒油，依口味加盐调味。嫩滑爽口，是传统早餐佳品。' WHERE id = 'liaoning_huludao_doufunao';
UPDATE dishes SET recipe = '猪里脊切片裹淀粉糊，入油锅炸至金黄捞出复炸至酥脆。锅中放糖、醋和番茄酱熬成糖醋汁，倒入肉片快速翻炒挂汁即成。' WHERE id = 'liaoning_jinzhou_guobaorou';
UPDATE dishes SET recipe = '玉米去皮洗净，刷上蜂蜜和黄油。放炭火上翻烤，边烤边刷油，烤至表面微焦金黄、香甜四溢即成。' WHERE id = 'liaoning_jinzhou_kaobaomi';
UPDATE dishes SET recipe = '羊肉串、鸡翅和蚕蛹提前腌制入味。上炭火烤架翻烤，边烤边刷油，撒上孜然和辣椒面，烤至外焦里嫩、满街飘香即成。' WHERE id = 'liaoning_jinzhou_shaobing';
UPDATE dishes SET recipe = '猪肉剁馅加鸡汤搅拌上劲，加盐调味。面粉和面擀皮，包入馅料捏成饺子。可水煮或蒸制，皮薄馅大，汤汁饱满鲜美。' WHERE id = 'liaoning_laobian_jiaozi';
UPDATE dishes SET recipe = '河蟹刷洗干净，放入蒸锅中，腹部朝上。大火蒸制十五分钟左右至蟹壳变红熟透。取出蘸姜醋汁食用，蟹黄饱满鲜美。' WHERE id = 'liaoning_panjin_heixie';
UPDATE dishes SET recipe = '鸡架洗净焯水，沥干后入油锅炸至金黄捞出。撒上孜然和辣椒面拌匀，也可放炭火上烤至焦香，外酥里嫩，是沈阳特色小吃。' WHERE id = 'liaoning_shenyang_jijia';
UPDATE dishes SET recipe = '鸡架烤熟或炸熟后撕成小块。热米饭盛碗，放上鸡架肉，撒辣椒面和孜然，淋少许酱油拌匀即可，酥香入味。' WHERE id = 'liaoning_shenyang_jijia_banfan';
UPDATE dishes SET recipe = '面条入沸水煮熟捞出放入碗中。浇上滚烫的鸡汤，打入一个鸡蛋，撒上香菜碎，加盐调味即可，汤鲜面滑。' WHERE id = 'liaoning_shenyang_siji_miantiao';
UPDATE dishes SET recipe = '黄豆煮熟捣碎，加面粉和盐拌匀，制成酱块发酵。发酵完成后加盐水入缸，日晒夜露数月，搅动至酱色红褐、酱香浓郁即成。' WHERE id = 'liaoning_yingkou_dajiang';
UPDATE dishes SET recipe = '虾仁和鱿鱼切碎，加韭菜末和盐调成馅料。面粉和面擀皮，包入馅料捏成饺子。入沸水煮至浮起，皮薄馅鲜，海鲜味浓。' WHERE id = 'liaoning_yingkou_haixian_jiaozi';
UPDATE dishes SET recipe = '琼脂加水煮至完全融化，加入白糖和果汁搅匀。倒入模具中放凉，再入冰箱冷藏至凝固。取出切块即可食用，清凉爽滑。' WHERE id = 'macau_agar_jelly';
UPDATE dishes SET recipe = '绿豆粉加杏仁碎、白糖和猪油揉成面团，分成小块压入模具成型。取出放入烤箱中烘烤至表面金黄、酥脆香甜即成。' WHERE id = 'macau_almond_cookie';
UPDATE dishes SET recipe = '马介休鱼肉撕碎，与蒸熟的土豆泥混合，加盐和胡椒调味。搓成球状，裹上蛋液和面包糠，入油锅炸至金黄酥脆即成。' WHERE id = 'macau_bacalhau_ball';
UPDATE dishes SET recipe = '鸭肉煮熟撕成丝，米饭铺在烤盘中，放上鸭肉丝，浇上番茄酱，撒上芝士。入烤箱烘烤至芝士融化金黄、香气四溢即成。' WHERE id = 'macau_baked_duck_rice';
UPDATE dishes SET recipe = '面粉加鸭蛋和碱水揉成硬面团，用竹竿反复压碾至面皮薄而筋道。切成细面条，入沸水中快煮至熟，捞出配高汤食用。' WHERE id = 'macau_bamboo_noodle';
UPDATE dishes SET recipe = '牛杂洗净切块焯水去腥。锅中放咖喱和辣椒炒香，加萝卜和牛杂，加水没过食材，大火烧开转小火慢炖至软烂入味即成。' WHERE id = 'macau_beef_offal';
UPDATE dishes SET recipe = '鸡肉切块焯水，大米淘洗。锅中加水放入鸡肉和米，大火烧开转小火慢煮至米粒开花、鸡肉酥烂。挤入柠檬汁，打入鸡蛋花搅匀即成。' WHERE id = 'macau_canja';
UPDATE dishes SET recipe = '鸡爪洗净剪去指甲，焯水后沥干。用豆豉、酱油和蒜调成酱汁，拌入鸡爪。上蒸笼大火蒸至软烂入味，酱香浓郁即成。' WHERE id = 'macau_chicken_feet';
UPDATE dishes SET recipe = '牛腩切块焯水，土豆和洋葱切块。锅中热油炒香咖喱粉，下牛腩翻炒上色，加椰浆和清水烧开。放入土豆和洋葱，小火慢炖至肉烂即成。' WHERE id = 'macau_curry_brisket';
UPDATE dishes SET recipe = '蛋黄加奶油、糖和面粉搅拌成蛋挞液，过滤备用。将挞液倒入挞皮中约八分满。入烤箱高温烘烤至表面焦糖色、挞皮酥脆即成。' WHERE id = 'macau_danta';
UPDATE dishes SET recipe = '鸡肉用椰浆、辣椒和花生碎腌制入味。放入烤箱中烤至表面微焦，刷上椰浆酱汁继续烤制。至熟透金黄，撒椰丝即成。' WHERE id = 'macau_feizhou_ji';
UPDATE dishes SET recipe = '螃蟹洗净切块。锅中热油炒香洋葱和蒜末，加咖喱粉炒出香味，下蟹块翻炒。倒入椰浆焖煮至蟹熟入味，大火收汁即成。' WHERE id = 'macau_gali_ji';
UPDATE dishes SET recipe = '辣椒和花生碎入锅炒香，加椰浆和虾酱小火熬煮。放入香料搅拌均匀，煮至浓稠成酱。可搭配烤鸡或肉类蘸食。' WHERE id = 'macau_galina_a_africana';
UPDATE dishes SET recipe = '鱼翅提前泡发处理干净，鸡肉和火腿切丝。锅中放入鸡汤烧开，加鱼翅和鸡丝小火慢煮至翅针软糯，调味后盛碗即可。' WHERE id = 'macau_jishi_fan';
UPDATE dishes SET recipe = '猪肉或牛肉切薄片，用蜂蜜和五香粉腌制入味。平铺在烤架上，低温烘烤至水分蒸发、肉质紧实。翻面继续烤至微焦即成。' WHERE id = 'macau_macau_jerky';
UPDATE dishes SET recipe = '马介休鱼肉用橄榄油浸泡去盐，撕成小块。土豆切条，入油锅炸至金黄。鱼肉和土豆配蒜蓉同炒或炸制，外酥内嫩。' WHERE id = 'macau_maliushi_bifengtang';
UPDATE dishes SET recipe = '土豆切丁，猪肉末备用。锅中热油，放入猪肉末炒散变色，加土豆丁翻炒，淋入酱油调味，炒至土豆软熟。配煎蛋食用。' WHERE id = 'macau_minchi';
UPDATE dishes SET recipe = '鸡蛋打散，入温油中炸至膨胀金黄捞出。糖浆加肉桂煮开，放入炸蛋浸泡吸收糖汁。至外甜内软、桂香四溢即成。' WHERE id = 'macau_pao_dan';
UPDATE dishes SET recipe = '花生炒熟去皮。锅中放白糖和麦芽糖小火熬至糖色微黄、能拉丝，倒入花生快速拌匀。倒在案板上压平切块，晾凉酥脆即成。' WHERE id = 'macau_peanut_candy';
UPDATE dishes SET recipe = '猪脚焯水去腥，姜拍扁。锅中放入甜醋烧开，加猪脚和姜大火煮沸转小火慢炖。煮至猪脚软烂入味，加入熟鸡蛋同煮片刻即成。' WHERE id = 'macau_pig_trotter_ginger';
UPDATE dishes SET recipe = '猪排拍松用盐和胡椒腌制，裹蛋液入油锅炸至金黄。热米饭盛盘，放上猪扒，配炒洋葱和煎蛋，淋酱汁食用。' WHERE id = 'macau_pork_chop_rice';
UPDATE dishes SET recipe = '鸡肉切块用盐腌制，土豆和洋葱切块。锅中热油炒香咖喱粉，下鸡肉翻炒上色，加椰浆和土豆烧开。小火炖至鸡肉酥烂，加橄榄点缀即成。' WHERE id = 'macau_portuguese_chicken';
UPDATE dishes SET recipe = '米饭铺在烤盘中，鸡蛋打散浇在饭上，放上火腿片，撒上芝士。入烤箱烘烤至芝士融化金黄、蛋液凝固即成，香浓可口。' WHERE id = 'macau_portuguese_egg_rice';
UPDATE dishes SET recipe = '鸡蛋打散，加牛奶、白糖和香草搅匀成布丁液，过滤气泡。倒入模具中，入烤箱隔水烘烤至凝固。取出冷却后冷藏，口感细腻滑嫩。' WHERE id = 'macau_pudding';
UPDATE dishes SET recipe = '叉烧、烧肉和烧鹅切片备用。热米饭盛盘，铺上各式烧味，配烫熟的青菜。淋上烧味酱汁即可食用，肉香饭热。' WHERE id = 'macau_roast_meat_rice';
UPDATE dishes SET recipe = '玛丽饼干擀碎成粉末，奶油加炼乳打发。容器中铺一层饼干碎，挤一层奶油，交替叠放至满。入冰箱冷藏数小时定型后食用。' WHERE id = 'macau_serradura';
UPDATE dishes SET recipe = '水蟹处理干净切块，大米淘洗。锅中加水和大米大火烧开转小火慢煮，待粥将成时放入蟹块和姜丝，煮至蟹熟粥稠即成。' WHERE id = 'macau_shuixiezhou';
UPDATE dishes SET recipe = '鸡肉切块用酱油和蚝油腌制。砂锅烧热，放入洋葱和青椒垫底，倒入鸡块大火焗烧。至锅中滋滋作响、鸡肉熟透入味即成。' WHERE id = 'macau_sizzling_chicken_pot';
UPDATE dishes SET recipe = '冬瓜蓉加白糖调成馅料。面粉分别做成水油皮和油酥皮，包入馅料压成饼状，表面刷蛋液撒芝麻。入烤箱烘烤至金黄酥脆即成。' WHERE id = 'macau_wife_cake';
UPDATE dishes SET recipe = '猪排拍松腌制后煎至两面金黄。面包对半切开，抹上黄油，夹入热猪扒。外脆内嫩，肉汁丰富，是澳门经典街头美食。' WHERE id = 'macau_zhubabao';
UPDATE dishes SET recipe = '柳蒿芽洗净焯水沥干。锅中热油，加蒜末爆香，放入柳蒿芽翻炒，淋辣椒油，加盐调味，炒匀出锅，清香爽口。' WHERE id = 'neimenggu_aermashan_liuhao';
UPDATE dishes SET recipe = '羊肉切大块冷水下锅，加入阿尔山矿泉水没过羊肉，放盐大火烧开撇去浮沫。转中火煮至羊肉熟透即可，原汁原味鲜嫩无比。' WHERE id = 'neimenggu_aermashan_shuizhurou';
UPDATE dishes SET recipe = '驼峰切块用盐和孜然腌制。先入锅中火煎至表面微焦，再入烤箱低温慢烤至熟透。外酥内软，脂香四溢，是草原珍馐。' WHERE id = 'neimenggu_alashan_tuofeng';
UPDATE dishes SET recipe = '羊肉剁馅加大葱末和盐调匀成馅。面粉用开水烫面和成团，擀成荷叶边薄皮，包入馅料收口成烧麦状。上蒸笼大火蒸熟，皮薄馅嫩。' WHERE id = 'neimenggu_baotou_shaomai';
UPDATE dishes SET recipe = '猪肉切片，豆角切段，土豆切条。锅中热油炒香肉片，加豆角和土豆翻炒，放入面条和适量水，盖锅盖小火焖至汤汁收干、面熟入味。' WHERE id = 'neimenggu_baotou_tieguo';
UPDATE dishes SET recipe = '糯米粉加水和成面团，包入红豆沙馅搓圆压扁。入五成热油锅中炸至金黄膨胀，捞出沥油，外酥内糯，甜香可口。' WHERE id = 'neimenggu_baotou_youtiao_gao';
UPDATE dishes SET recipe = '驴肉和猪肉加香料卤制入味至酥烂。面粉做成酥皮饼，入炉烘烤至金黄酥脆。将卤肉夹入热饼中食用，外酥肉烂，香浓味美。' WHERE id = 'neimenggu_chifeng_duijia';
UPDATE dishes SET recipe = '羊血加荞面和葱花搅匀灌入羊肠中扎紧。放入开水锅中小火慢煮至血肠浮起熟透，捞出切段食用，蘸蒜酱更佳。' WHERE id = 'neimenggu_chifeng_xuechang_2';
UPDATE dishes SET recipe = '羊肉切大块放入冷水锅中，加盐大火烧开撇去浮沫。转中火煮至羊肉熟透捞出，手抓食用，蘸韭菜花酱，鲜嫩原味。' WHERE id = 'neimenggu_eerduosi_shouzhua';
UPDATE dishes SET recipe = '面粉加酸奶、白糖和芝麻揉成面团，擀成圆饼状。放入平底锅或烤炉中烙烤至两面金黄，外酥内软，酸甜可口。' WHERE id = 'neimenggu_eerduosi_suanlai_bing';
UPDATE dishes SET recipe = '鲜牛奶小火煮开放凉至温热，加入酸奶引子搅匀，保温发酵至凝固。拌入蓝莓和白糖，酸甜适口，果香奶香交融。' WHERE id = 'neimenggu_hulunbeier_lanmei_suannai';
UPDATE dishes SET recipe = '面粉加啤酒花、牛奶和黄油揉成面团发酵至两倍大。整形后放入烤箱烘烤至外皮焦硬、内部松软。切片食用，麦香浓郁。' WHERE id = 'neimenggu_hulunbeier_lieba';
UPDATE dishes SET recipe = '铜锅加清汤烧开，羊肉片入锅涮至变色即捞出。蘸芝麻酱、韭菜花和腐乳调成的蘸料食用，鲜嫩爽滑，原汁原味。' WHERE id = 'neimenggu_hulunbeier_rou';
UPDATE dishes SET recipe = '面粉加胡麻油、盐和芝麻揉成面团，分成小剂子擀成圆饼。放入烤炉中烘烤至两面金黄、层次分明、外酥内软即成。' WHERE id = 'neimenggu_hushi_beizi';
UPDATE dishes SET recipe = '牛腱肉焯水去血沫。锅中放酱油、八角、桂皮和花椒调成卤汁，放入牛肉大火烧开转小火慢卤至入味。捞出浸泡数小时，切片即食。' WHERE id = 'neimenggu_jiangzha';
UPDATE dishes SET recipe = '整羊洗净，用孜然、盐和香料里外涂抹腌制。上烤架用炭火慢烤数小时，边烤边刷油翻面，至皮酥肉嫩、金黄焦香即成。' WHERE id = 'neimenggu_kaoquan_yang';
UPDATE dishes SET recipe = '面粉加白糖、牛奶和鸡蛋揉成面团，分成小剂子搓成条状或花形。入五成热油锅中炸至金黄膨胀，捞出沥油，香甜酥脆。' WHERE id = 'neimenggu_mianhou';
UPDATE dishes SET recipe = '砖茶煮出浓茶汤滤去茶渣。茶汤倒入锅中加鲜牛奶小火煮沸，放入黄油和盐搅匀，加入炒米同煮。咸香醇厚，是蒙古族传统饮品。' WHERE id = 'neimenggu_naicha';
UPDATE dishes SET recipe = '鲜牛奶发酵成酸奶后倒入锅中小火加热，搅拌至蛋白质凝固析出。捞出凝乳压成块状，晾干定型即成。口感酸甜，奶香浓郁。' WHERE id = 'neimenggu_nailao';
UPDATE dishes SET recipe = '羊肉剁馅加大葱末和盐调匀。面粉用开水烫面和成团，擀成荷叶边薄皮，包入馅料收口不封顶。上蒸笼大火蒸至皮透馅熟即成。' WHERE id = 'neimenggu_shaomai';
UPDATE dishes SET recipe = '羊肉带骨切大块，放入冷水锅中加盐大火烧开。撇去浮沫后煮至熟透，捞出装盘。手把骨头食用，蘸盐或韭菜花酱，肉嫩汤鲜。' WHERE id = 'neimenggu_shoubab_rou';
UPDATE dishes SET recipe = '鲜牛奶煮开放凉至温热，加入酸奶引子搅匀，置于温暖处发酵数小时至凝固。加白糖搅匀食用，酸甜浓稠，营养丰富。' WHERE id = 'neimenggu_suan_nai';
UPDATE dishes SET recipe = '砖茶煮出浓茶汤滤渣。倒入铁锅加鲜牛奶煮沸，放入黄油和盐搅匀，撒入炒米。小火慢煮至茶乳交融，咸香醇厚。' WHERE id = 'neimenggu_tongliao_guocha';
UPDATE dishes SET recipe = '面粉加白糖、牛奶和鸡蛋揉成面团，分成小剂子搓成条状或扭花形。入五成热油锅中炸至金黄酥脆，捞出沥油即成。' WHERE id = 'neimenggu_tongliao_mian_guozha';
UPDATE dishes SET recipe = '羊肉带骨切大块入冷水锅，加盐大火烧开撇去浮沫。煮至熟透捞出装盘，手抓食用，蘸韭菜花酱，鲜嫩多汁。' WHERE id = 'neimenggu_tongliao_shoubarou';
UPDATE dishes SET recipe = '莜面加开水烫熟和成面团，搓成小窝窝状整齐码在蒸笼中。上锅大火蒸熟，配羊肉土豆臊子或辣椒蘸料食用，筋道爽滑。' WHERE id = 'neimenggu_wulanchabu_wowo';
UPDATE dishes SET recipe = '鲜牛奶倒入锅中小火慢煮，不搅动，待表面凝结一层奶皮。轻轻挑起晾干，反复多次积累厚度。奶皮金黄香浓，是蒙古族特色奶制品。' WHERE id = 'neimenggu_wulanhaote_naipizi';
